allow:
Bash(powershell.exe -Command "
try {
  \\$resp = Invoke-WebRequest -Uri 'http://localhost:2580/' -UseBasicParsing -TimeoutSec 5
  Write-Host \('Status: ' + \\$resp.StatusCode\)
  Write-Host \\$resp.Content
} catch {
  Write-Host \('Error: ' + \\$_.Exception.Message\)
}
" 2>&1)

